import React, { useEffect, useState } from "react";

function BusMap() {
  const [buses, setBuses] = useState([]);
  const [status, setStatus] = useState("Connecting...");

  useEffect(() => {
    // Connect to backend WebSocket
    const ws = new WebSocket("ws://127.0.0.1:8000/ws/buses");

    ws.onopen = () => {
      console.log("✅ Connected to WebSocket");
      setStatus("Connected ✅");
    };

    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        console.log("📡 Received:", data);

        // Backend sends buses as an object -> convert to array
        setBuses(Object.values(data));
      } catch (err) {
        console.error("❌ Error parsing WS data", err);
      }
    };

    ws.onclose = () => {
      console.log("⚠️ WebSocket closed. Reconnecting in 5s...");
      setStatus("Disconnected ⚠️");
      setTimeout(() => {
        window.location.reload(); // simple reconnect
      }, 5000);
    };

    ws.onerror = (err) => {
      console.error("🚨 WebSocket error", err);
      setStatus("Error 🚨");
    };

    return () => ws.close();
  }, []);

  return (
    <div style={{ padding: "1rem" }}>
      <h1>🚍 Live Bus Tracker</h1>
      <p>Status: {status}</p>
      <p>Total buses: {buses.length}</p>

      <ul>
        {buses.map((bus) => (
          <li key={bus.id}>
            🚌 ID: {bus.id} | Route: {bus.route} | Speed: {bus.speed.toFixed(1)} mph | Status:{" "}
            <strong>{bus.status}</strong>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default BusMap;
